impl Solution { pub fn maximum_length(nums: Vec<i32>, k: i32) -> i32 { let (n, k) = (nums.len(), k as usize); let mut black_dp = vec![vec![0; k + 1]; n]; let mut black_ans = 0; for i in 0..n { black_dp[i][0] = 1; for j in 0..i { for diff in 0..=k { if nums[i] == nums[j] { black_dp[i][diff] = black_dp[i][diff].max(black_dp[j][diff] + 1); } else if diff > 0 { black_dp[i][diff] = black_dp[i][diff].max(black_dp[j][diff - 1] + 1); } } } for diff in 0..=k { black_ans = black_ans.max(black_dp[i][diff]); } } black_ans } }